# -*- coding: utf-8 -*-
import os

outpath = r'd:\工作备份\ptrade\trae work\创造力大塞\gaosan-complete.js'

# 读取现有内容
with open(outpath, 'r', encoding='utf-8') as f:
    content = f.read()

# 找到最后一个 '}' 的位置，将其替换为新内容
# 实际上我们需要保留结构：'高三': { '语文': [...], '数学': [...] } → 需要替换最后一个 }

# 先找到 '数学' 数组结尾后的部分
# 简单做法：重新组织
parts = content.split("'数学':")
header = parts[0] + "'数学':"
# 找到 math 数组的结尾
math_content = parts[1]
# 找到 math 数组最后一个 ']' 位置
idx = math_content.rindex(']')
math_array = math_content[:idx+1]
rest = math_content[idx+1:]  # 应该是 '\n}'

# 构造完整内容
full_content = header + math_array + ',\n'

# 现在追加其他科目
# ========================================
# 英语
